CREATE TABLE public.bot_sessions (id uuid NOT NULL DEFAULT uuid_generate_v4(), phone_number text NOT NULL, current_step text NOT NULL, data jsonb DEFAULT '{}'::jsonb, updated_at timestamp with time zone DEFAULT now());

CREATE TABLE public.chat_actividad (ultimo_mensaje timestamp with time zone, chat_id text NOT NULL);

CREATE TABLE public.chat_histories (created_at timestamp with time zone DEFAULT now(), message jsonb, session_id text, id bigint NOT NULL);

CREATE TABLE public.citas (auto_cancelada boolean DEFAULT false, tipo text DEFAULT 'cita'::text, estado text DEFAULT 'confirmada'::text, fecha_hora_fin timestamp with time zone, fecha_hora_inicio timestamp with time zone, nombre_cliente_manual text, cliente_id bigint, created_at timestamp with time zone DEFAULT now(), estado_pago text DEFAULT 'pendiente'::text, fotos_referencia ARRAY, descripcion text, fecha_completado timestamp with time zone, total_pagado numeric DEFAULT 0, aviso_hora boolean DEFAULT false, aviso_20min boolean DEFAULT false, servicio text, telefono text, stripe_payment_intent_id text, empleado_id bigint, sucursal_id bigint, negocio_id uuid, id bigint NOT NULL, cliente_email text, monto_total numeric, stripe_session_id text);

CREATE TABLE public.citas_servicios (servicio_id bigint, precio_actual numeric DEFAULT 0, id bigint NOT NULL, cita_id bigint);

CREATE TABLE public.clientes_bot (sucursal_id bigint, email text, id bigint NOT NULL, negocio_id uuid, nombre text, telefono text, chat_id text, plataforma text DEFAULT 'manual'::text, created_at timestamp with time zone DEFAULT now());

CREATE TABLE public.empleado_servicios (empleado_id bigint, servicio_id bigint, id bigint NOT NULL);

CREATE TABLE public.empleados (rol text, created_at timestamp with time zone DEFAULT now(), especialidad text, sucursal_id bigint, nombre text NOT NULL, negocio_id uuid, id bigint NOT NULL);

CREATE TABLE public.horarios_sucursal (hora_descanso_inicio time without time zone, id bigint NOT NULL, sucursal_id bigint, dia_semana integer, hora_inicio time without time zone, hora_fin time without time zone, created_at timestamp with time zone DEFAULT now(), activo boolean DEFAULT true, duracion_descanso_minutos integer DEFAULT 0);

CREATE TABLE public.inbox_telegram (message_id text, created_at timestamp with time zone DEFAULT now(), id bigint NOT NULL, chat_id text, message_text text);

CREATE TABLE public.n8n_chat_histories (createdAt timestamp with time zone DEFAULT now(), id integer NOT NULL DEFAULT nextval('n8n_chat_histories_id_seq'::regclass), session_id text NOT NULL, message jsonb NOT NULL);

CREATE TABLE public.negocio_suscripciones (fecha_fin_prueba timestamp with time zone, fecha_fin_periodo timestamp with time zone, created_at timestamp with time zone DEFAULT now(), updated_at timestamp with time zone DEFAULT now(), stripe_subscription_id text, tipo_chatbot character varying(10) DEFAULT 'web'::character varying, negocio_id uuid NOT NULL, plan_id integer, estado text NOT NULL DEFAULT 'trial'::text);

CREATE TABLE public.negocios (stripe_customer_id text, id uuid NOT NULL DEFAULT uuid_generate_v4(), nombre text NOT NULL, created_at timestamp with time zone DEFAULT now());

CREATE TABLE public.planes (activo boolean DEFAULT true, precio_mxn numeric NOT NULL, nombre text NOT NULL, codigo text NOT NULL, id integer NOT NULL DEFAULT nextval('planes_id_seq'::regclass), limite_sucursales integer NOT NULL, limite_empleados_por_sucursal integer, descripcion text);

CREATE TABLE public.servicios (link_pago text, id bigint NOT NULL, negocio_id uuid, sucursal_id bigint, nombre text NOT NULL, descripcion text, precio_base numeric DEFAULT 0, duracion_aprox_minutos integer DEFAULT 30, created_at timestamp with time zone DEFAULT now(), imagen_url text);

CREATE TABLE public.sucursales (created_at timestamp with time zone DEFAULT now(), direccion text, nombre text NOT NULL, negocio_id uuid, id bigint NOT NULL, stripe_onboarding_complete boolean DEFAULT false, stripe_account_id text, telefono character varying(20), cuenta_password text, cuenta_email text);

CREATE TABLE public.usuarios_perfiles (avatar_url text, nombre text, id uuid NOT NULL, negocio_id uuid, created_at timestamp with time zone DEFAULT now(), sucursal_id bigint, email text, rol text DEFAULT 'dueño'::text);

